1	<script lang="ts">
2		import type { PageData } from './$types';
3		import { goto } from '$app/navigation';
4		import { resolve } from '$app/paths';
5		import { page } from '$app/stores';
6		import D3Graph from '$lib/components/D3Graph.svelte';
7		import IntegrityPanel from '$lib/components/IntegrityPanel.svelte';
8		import type { GraphDocument } from './+page';
9	
10		let { data }: { data: PageData } = $props();
11	
12		const issues = $derived(data.graph.issues ?? []);
13	
14		// Filter state — derived from URL search params
15		let activeMediaTypes = $state<string[]>([]);
16		let activeStaleness = $state<string[]>([]);
17	
18		// Sync filter state from URL on init
19		$effect(() => {
20			const urlMediaType = $page.url.searchParams.get('mediaType');
21			const urlStaleness = $page.url.searchParams.get('staleness');
22			activeMediaTypes = urlMediaType ? urlMediaType.split(',').filter(Boolean) : [];
23			activeStaleness = urlStaleness ? urlStaleness.split(',').filter(Boolean) : [];
24		});
25	
26		// Filtered nodes: apply active filter chips
27		const visibleNodes = $derived.by(() => {
28			let docs: GraphDocument[] = data.graph.documents;
29			if (activeMediaTypes.length > 0) {
30				docs = docs.filter((d) => activeMediaTypes.includes(d.mediaType));
31			}
32			if (activeStaleness.length > 0) {
33				docs = docs.filter((d) => activeStaleness.includes(d.staleness));
34			}
35			return docs;
36		});
37	
38		const visibleIds = $derived(new Set(visibleNodes.map((d) => d.id)));
39	
40		// Only include links between visible nodes
41		const visibleLinks = $derived(
42			data.graph.documents
43				.flatMap((doc) => doc.dependsOn.map((depId) => ({ source: doc.id, target: depId })))
44				.filter((l) => visibleIds.has(l.source) && visibleIds.has(l.target))
45		);
46	
47		function updateFilters(mediaTypes: string[], staleness: string[]) {
48			const url = new URL($page.url);
49			if (mediaTypes.length > 0) url.searchParams.set('mediaType', mediaTypes.join(','));
50			else url.searchParams.delete('mediaType');
51			if (staleness.length > 0) url.searchParams.set('staleness', staleness.join(','));
52			else url.searchParams.delete('staleness');
53			goto(url.pathname + url.search, { replaceState: true, keepFocus: true });
54		}
55	
56		function toggleMediaType(mt: string) {
57			const next = activeMediaTypes.includes(mt)
58				? activeMediaTypes.filter((m) => m !== mt)
59				: [...activeMediaTypes, mt];
60			updateFilters(next, activeStaleness);
61		}
62	
63		function toggleStaleness(s: string) {
64			const next = activeStaleness.includes(s)
65				? activeStaleness.filter((v) => v !== s)
66				: [...activeStaleness, s];
67			updateFilters(activeMediaTypes, next);
68		}
69	
70		function handleNodeClick(node: { path: string; mediaType?: string; id: string }) {
71			const p = $page.params as Record<string, string>;
72			if (node.mediaType === 'text/markdown' || !node.mediaType) {
73				goto(
74					resolve(
75						`/nodes/${p['nodeId']}/projects/${p['projectId']}/documents/${node.path.split('/').map(encodeURIComponent).join('/')}`
76					)
77				);
78			} else {
79				goto(
80					resolve(
81						`/nodes/${p['nodeId']}/projects/${p['projectId']}/artifacts/${encodeURIComponent('doc:' + node.id)}`
82					)
83				);
84			}
85		}
86	
87		function handleTransformChange(t: { x: number; y: number; k: number }) {
88			const url = new URL($page.url);
89			url.searchParams.set('zoom', t.k.toFixed(3));
90			url.searchParams.set('pan', `${t.x.toFixed(1)},${t.y.toFixed(1)}`);
91			history.replaceState(null, '', url.toString());
92		}
93	
94		const MEDIA_TYPE_CHIPS = [
95			{ label: 'Markdown', value: 'text/markdown' },
96			{ label: 'Image', value: 'image/*' },
97			{ label: 'Unknown', value: 'unknown' }
98		];
99	
100		const STALENESS_CHIPS = [
101			{ label: 'Fresh', value: 'fresh' },
102			{ label: 'Stale', value: 'stale' },
103			{ label: 'Missing', value: 'missing' }
104		];
105	</script>
106	
107	<div class="flex flex-col gap-4" style="height: calc(100dvh - 40px - 3rem)">
108		<div class="flex shrink-0 items-center justify-between">
109			<div class="flex items-center gap-3">
110				<h1 class="text-xl font-semibold dark:text-white">Document Graph</h1>
111				{#if issues.length > 0}
112					<span
113						data-testid="integrity-badge"
114						class="rounded-full bg-amber-200 px-2 py-0.5 text-xs font-medium text-amber-900 dark:bg-amber-800 dark:text-amber-100"
115					>
116						{issues.length}
117						{issues.length === 1 ? 'issue' : 'issues'}
118					</span>
119				{/if}
120			</div>
121			<div class="flex items-center gap-4">
122				<a
123					href={`/nodes/${$page.params['nodeId']}/projects/${$page.params['projectId']}/artifacts?mediaType=text%2Fmarkdown`}
124					class="text-sm text-accent-lever hover:underline dark:text-dark-accent-lever"
125				>
126					Back to documents
127				</a>
128				<span class="text-sm text-gray-700 dark:text-gray-300">
129					{visibleNodes.length} nodes &middot; {visibleLinks.length} edges
130				</span>
131			</div>
132		</div>
133	
134		<!-- Filter chips -->
135		<div class="flex shrink-0 flex-wrap gap-2">
136			<span class="self-center text-xs text-fg-muted dark:text-dark-fg-muted">Type:</span>
137			{#each MEDIA_TYPE_CHIPS as chip}
138				{@const active = activeMediaTypes.includes(chip.value)}
139				<button
140					onclick={() => toggleMediaType(chip.value)}
141					data-testid={`filter-mediatype-${chip.value.replace(/[^a-z]/gi, '-')}`}
142					class="rounded-full px-3 py-0.5 font-label-caps text-label-caps uppercase transition-colors {active
143						? 'bg-accent-lever text-white dark:bg-dark-accent-lever'
144						: 'bg-bg-surface text-fg-muted hover:bg-bg-elevated hover:text-fg-ink dark:bg-dark-bg-surface dark:text-dark-fg-muted dark:hover:bg-dark-bg-elevated dark:hover:text-dark-fg-ink'}"
145				>
146					{chip.label}
147				</button>
148			{/each}
149			<span class="self-center text-xs text-fg-muted dark:text-dark-fg-muted">Staleness:</span>
150			{#each STALENESS_CHIPS as chip}
151				{@const active = activeStaleness.includes(chip.value)}
152				<button
153					onclick={() => toggleStaleness(chip.value)}
154					data-testid={`filter-staleness-${chip.value}`}
155					class="rounded-full px-3 py-0.5 font-label-caps text-label-caps uppercase transition-colors {active
156						? 'bg-accent-lever text-white dark:bg-dark-accent-lever'
157						: 'bg-bg-surface text-fg-muted hover:bg-bg-elevated hover:text-fg-ink dark:bg-dark-bg-surface dark:text-dark-fg-muted dark:hover:bg-dark-bg-elevated dark:hover:text-dark-fg-ink'}"
158				>
159					{chip.label}
160				</button>
161			{/each}
162		</div>
163	
164		{#if issues.length > 0}
165			<IntegrityPanel {issues} pathToDocId={data.graph.pathToDocId} />
166		{/if}
167	
168		{#if data.graph.documents.length === 0}
169			<div class="flex flex-1 items-center justify-center text-gray-700 dark:text-gray-300">
170				No documents in graph.
171			</div>
172		{:else}
173			<div class="min-h-0 flex-1 overflow-hidden rounded-lg border border-gray-200 dark:border-gray-700">
174				<D3Graph
175					nodes={visibleNodes}
176					links={visibleLinks}
177					onNodeClick={handleNodeClick}
178					initialTransform={data.initialTransform}
179					onTransformChange={handleTransformChange}
180					highlightNodeId={data.highlightNodeId}
181				/>
182			</div>
183		{/if}
184	</div>
