26	function relLuminance(hex: string): number {
27		const m = hex.replace('#', '');
28		const r = parseInt(m.slice(0, 2), 16);
29		const g = parseInt(m.slice(2, 4), 16);
30		const b = parseInt(m.slice(4, 6), 16);
31		return 0.2126 * srgbChannel(r) + 0.7152 * srgbChannel(g) + 0.0722 * srgbChannel(b);
32	}
33	
34	function contrast(a: string, b: string): number {
35		const la = relLuminance(a);
36		const lb = relLuminance(b);
37		const [hi, lo] = la > lb ? [la, lb] : [lb, la];
38		return (hi + 0.05) / (lo + 0.05);
39	}
